var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래서, 충성스러운 직원들은 버려 두고 그 쓸모없는 여자랑 둘이 도망쳤단 말이야?","JPN":"それで、献身的な社員たちを見捨てて何の役にも立たない女と二人で逃げたってこと？","ENG":"So you abandoned your loyal employees and ran off with that useless woman?","TWN":"所以你的意思是，你扔下那些忠心耿耿的員工，帶著沒什麼用的女人逃跑嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"사랑의 도피라기엔 너무 볼썽사납네.","JPN":"愛の逃避行というには見苦しいわね。","ENG":"Not exactly the most romantic way to elope, if you ask me.","TWN":"這是什麼一點也不感人的愛情故事？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"목숨 바쳐 나를 지키라고 고용한 놈들이야. 그동안 받아먹은 돈값은 해야지.","JPN":"命をかけて僕を守るために雇われたやつらだ。これまでこっちが払った金の分、働いてもらわないと。","ENG":"I hired those fools to risk their lives to save me. It's time they earned their keep.","TWN":"我花錢請他們來就是要為我擋子彈的，拿錢辦事很正常吧。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"사채꾼 하나도 어떻게 못 하면 해고 사유가 될 테니까.","JPN":"闇金業者の一人も対応できないやつらは解雇されても言い訳できないだろ。","ENG":"If they can't handle some lowly loan shark, they're fired.","TWN":"如果連區區一個高利貸都搞不定，就等著回家吃自己吧。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"상상만 해도 비극적인걸. 병상에 누운 채로 보상 한 푼 못 받고 해고 통지를 받는 풍경이란.","JPN":"想像するだけで悲劇的だわ。病床に伏せたまま補償は\\n1クレジットも支払われず、解雇通知だけを受け取る状況がね。","ENG":"It brings a tear to my eyes to imagine how it'll go down. Getting sacked without so much as a penny to pay their hospital bills.","TWN":"光想就覺得很慘，躺在病床上，沒有得到獎賞，只有收到離職通知。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭘 자기는 예외인 것처럼 시시덕거리지?","JPN":"なぜ自分は例外だと思い込んでいるんだ？","ENG":"Save the sarcasm. What makes you think you'll be the exception?","TWN":"你怎麼一副事不關己的樣子？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"모가지가 위험한 건 너도 마찬가지다, 셰나.","JPN":"首になるかもしれないのはお前も同じだ、シェナ。","ENG":"Your career is just as precarious right now, Shena.","TWN":"你以為你的位置很穩嗎，世娜？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"경호실장 주제에 그 빌어먹을 사채꾼이 내 소재를 알아낸 줄도 몰랐다는 게 말이 되나?","JPN":"警護室長のくせに、あのクソ闇金業者が僕の居場所を突き止めたことも知らなかったなんてあり得ないだろ？","ENG":"What kind of a head of security didn't even realize that damn loan shark found my location?","TWN":"身為護衛室長，竟然沒發現她找到我的下落，會不會太誇張？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"말했잖아. 그러게 연구소든 어디든 가면 좀 잘 쓰고 다니라니까.","JPN":"だから言ったでしょ。研究所だけじゃなくて、どこに行ってもちゃんと仮面を被りなさいって。","ENG":"I'd hate to say I told you so… But you really should have kept that mask on.","TWN":"我不是有提醒你嗎～叫你不管是要去研究所，還是去哪裡，面具都要戴好戴滿。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"가면만 쓰고 다녔으면 꼬리가 잡힐 일도 없었을 거 아냐?","JPN":"仮面さえちゃんと被っていれば、感づかれることはなかったじゃない？","ENG":"You wouldn't have had to deal with this if you had kept your face covered.","TWN":"要是你有聽話乖乖戴面具，還會被人家抓到小辮子嗎？你說說看？？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"닥쳐.","JPN":"黙れ。","ENG":"Shut up,","TWN":"閉嘴！"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"네 핑계는 질리게 들었어. 내 인내심이 한계에 다다를 때까지 말이야.","JPN":"お前の言い訳はもううんざりだ。こっちは我慢の限界なんだよ。","ENG":"I'm sick and tired of your excuses. I've simply had it with you.","TWN":"我不想再聽你的藉口，不要挑戰我的耐心！"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"상부로부터 날 지키라는 지시를 받지 않았나?","JPN":"上層部から僕を守れという指示を受けているだろ？","ENG":"Have you not received the strictest orders from the leadership to protect me?","TWN":"你沒收到上面的指示嗎？叫你好好保護我？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내 털끝 하나라도 다치면 어떻게 될지는 네가 제일 잘 알고 있을 텐데?","JPN":"僕が怪我でもしたらどうなるか、お前が一番知っているはずだ。","ENG":"You know better than anyone what would happen if there's so much as a scratch on me.","TWN":"萬一傷到我一根寒毛會發生甚麼事，你應該比任何人都清楚吧？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"같잖은 장난 그만치고 당장 와서 나를 경호해. 계속 그따위로 굴면 상부에 보고하겠어.","JPN":"のらりくらりと逃げずに今すぐこっちで僕を警護しろ。ずっとその調子なら上層部に報告するぞ。","ENG":"Now quit goofing around and come secure me at once. Otherwise, I'll report you to leadership.","TWN":"不要再跟我嘻皮笑臉的，立刻過來保護我！你再這樣我就要跟上面報告！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 어떡할까. 위에다 일러바치면 내 입장이 무척 난처해지는데.","JPN":"フフッ。どうしようかな。上に告げ口されたらとっても困っちゃうわ。","ENG":"Oh my. What should I do? You'll put me in a most difficult situation if you tattle on me.","TWN":"呵呵，我好怕喔，你跟上面打小報告的話，我的處境會變得很困難。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"걱정 마. 그렇게 말할 것 같아서 지금 병력을 데리고 그리로 가는 중이니까.","JPN":"もう心配しないで。そう言われると思って、今兵士たちを連れてそっちに向っている途中よ。","ENG":"Don't worry. I had a feeling you'd say that, so I'm sending troops your way.","TWN":"放心吧，我就怕會這樣，所以現在正帶著人去找你。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};